package main

import (
	"log"
	"os"
	"os/signal"
	"syscall"
	"time"

	"notification-service/internal/consumer"
)

const (
	retryDelay = 5 * time.Second
	maxRetries = 10
)

func start(attempt int) {
	if attempt > maxRetries {
		log.Fatalf("[app] Failed to start after %d attempts. Exiting.", maxRetries)
	}

	if err := consumer.Start(); err != nil {
		log.Printf("[app] Attempt %d failed, retrying in %s... %v", attempt, retryDelay, err)
		time.Sleep(retryDelay)
		start(attempt + 1)
		return
	}

	log.Println("[app] Notification service started")
}

func main() {
	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGTERM, syscall.SIGINT)

	go func() {
		sig := <-quit
		log.Printf("[app] Received %s, shutting down gracefully", sig)
		os.Exit(0)
	}()

	start(1)
}
